# solution.py

"""
LanguageCollaborator - A collaborative language learning platform.

Facilitates collaborative learning among multiple users by providing
interactive language exercises, real-time feedback, and peer review capabilities.
"""

import hashlib
import secrets
import threading
import time
import re
import unittest
from datetime import datetime
from enum import Enum
from typing import Dict, List, Optional, Any


# ============================================================================
# Models
# ============================================================================

class ExerciseType(Enum):
    GRAMMAR_QUIZ = "grammar_quiz"
    VOCABULARY_TEST = "vocabulary_test"
    WRITING_PROMPT = "writing_prompt"


class User:
    """Represents a registered user in the system."""

    def __init__(self, username: str, password: str, display_name: str = ""):
        self.username = username
        self.password_hash = self._hash_password(password)
        self.display_name = display_name or username
        self.created_at = datetime.now()
        self.is_active = True

    @staticmethod
    def _hash_password(password: str) -> str:
        salt = "lc_salt_2024"
        return hashlib.sha256(f"{salt}{password}".encode()).hexdigest()

    def verify_password(self, password: str) -> bool:
        return self.password_hash == self._hash_password(password)


class Exercise:
    """Represents a language exercise created by a user."""

    _id_counter = 0
    _id_lock = threading.Lock()

    def __init__(self, creator: str, exercise_type: ExerciseType,
                 title: str, content: Dict[str, Any],
                 shared_with: Optional[List[str]] = None):
        with Exercise._id_lock:
            Exercise._id_counter += 1
            self.exercise_id = Exercise._id_counter
        self.creator = creator
        self.exercise_type = exercise_type
        self.title = title
        self.content = content
        self.shared_with: List[str] = shared_with or []
        self.is_public = False
        self.created_at = datetime.now()
        self.submissions: List[Dict[str, Any]] = []
        self.peer_reviews: List[Dict[str, Any]] = []


class Session:
    """Represents an active user session."""

    def __init__(self, username: str):
        self.token = secrets.token_hex(32)
        self.username = username
        self.created_at = datetime.now()
        self.last_activity = datetime.now()
        self.is_valid = True


# ============================================================================
# Feedback Engine
# ============================================================================

class FeedbackEngine:
    """Provides real-time feedback on language exercises."""

    COMMON_GRAMMAR_RULES = {
        "their/there/they're": {
            "pattern": r"\b(their|there|they're)\b",
            "suggestion": "Check usage: 'their' (possessive), 'there' (place), 'they're' (they are)"
        },
        "its/it's": {
            "pattern": r"\b(its|it's)\b",
            "suggestion": "Check usage: 'its' (possessive), 'it's' (it is)"
        },
        "subject-verb agreement": {
            "pattern": r"\b(he|she|it)\s+(have|are|were)\b",
            "suggestion": "Check subject-verb agreement: singular subjects need singular verbs"
        },
        "double_negative": {
            "pattern": r"\b(don't|doesn't|didn't|won't|can't|isn't|aren't)\s+\w*\s*(no|nothing|nobody|nowhere|never)\b",
            "suggestion": "Avoid double negatives in standard English"
        },
    }

    VOCABULARY_HINTS = {
        "good": ["excellent", "outstanding", "superb", "remarkable"],
        "bad": ["terrible", "awful", "dreadful", "inferior"],
        "big": ["enormous", "vast", "immense", "substantial"],
        "small": ["tiny", "miniature", "minute", "compact"],
        "happy": ["elated", "jubilant", "ecstatic", "delighted"],
        "sad": ["melancholy", "sorrowful", "despondent", "dejected"],
    }

    @classmethod
    def evaluate_quiz(cls, questions: List[Dict], answers: List[str]) -> Dict[str, Any]:
        """Evaluate grammar quiz answers and provide feedback."""
        if not questions or not answers:
            return {"score": 0, "total": 0, "feedback": [], "percentage": 0.0}

        results = []
        correct_count = 0
        total = min(len(questions), len(answers))

        for i in range(total):
            question = questions[i]
            user_answer = answers[i].strip().lower() if i < len(answers) else ""
            correct_answer = question.get("correct_answer", "").strip().lower()
            is_correct = user_answer == correct_answer

            if is_correct:
                correct_count += 1

            results.append({
                "question_index": i,
                "question": question.get("question", ""),
                "user_answer": answers[i] if i < len(answers) else "",
                "correct_answer": question.get("correct_answer", ""),
                "is_correct": is_correct,
                "explanation": question.get("explanation", "")
            })

        percentage = (correct_count / total * 100) if total > 0 else 0.0

        return {
            "score": correct_count,
            "total": total,
            "percentage": round(percentage, 1),
            "feedback": results,
            "passed": percentage >= 60.0
        }

    @classmethod
    def evaluate_vocabulary(cls, word_pairs: List[Dict], answers: List[str]) -> Dict[str, Any]:
        """Evaluate vocabulary test answers."""
        if not word_pairs or not answers:
            return {"score": 0, "total": 0, "feedback": [], "percentage": 0.0}

        results = []
        correct_count = 0
        total = min(len(word_pairs), len(answers))

        for i in range(total):
            pair = word_pairs[i]
            user_answer = answers[i].strip().lower() if i < len(answers) else ""
            correct_answers = [a.strip().lower() for a in pair.get("accepted_answers", [])]
            if not correct_answers:
                correct_answers = [pair.get("answer", "").strip().lower()]

            is_correct = user_answer in correct_answers

            if is_correct:
                correct_count += 1

            hint = ""
            if not is_correct and user_answer:
                for correct in correct_answers:
                    if user_answer[:3] == correct[:3]:
                        hint = f"Close! The answer starts with '{correct[:3]}...'"
                        break

            results.append({
                "question_index": i,
                "word": pair.get("word", ""),
                "user_answer": answers[i] if i < len(answers) else "",
                "correct_answers": correct_answers,
                "is_correct": is_correct,
                "hint": hint
            })

        percentage = (correct_count / total * 100) if total > 0 else 0.0

        return {
            "score": correct_count,
            "total": total,
            "percentage": round(percentage, 1),
            "feedback": results,
            "passed": percentage >= 60.0
        }

    @classmethod
    def evaluate_writing(cls, text: str) -> Dict[str, Any]:
        """Provide feedback on a writing submission."""
        if not text or not text.strip():
            return {
                "word_count": 0,
                "grammar_issues": [],
                "vocabulary_suggestions": [],
                "overall_feedback": "No text provided for evaluation."
            }

        words = text.split()
        word_count = len(words)
        sentences = [s.strip() for s in re.split(r'[.!?]+', text) if s.strip()]
        sentence_count = len(sentences)

        grammar_issues = []
        for rule_name, rule in cls.COMMON_GRAMMAR_RULES.items():
            matches = re.finditer(rule["pattern"], text, re.IGNORECASE)
            for match in matches:
                grammar_issues.append({
                    "rule": rule_name,
                    "position": match.start(),
                    "text": match.group(),
                    "suggestion": rule["suggestion"]
                })

        vocabulary_suggestions = []
        for word in words:
            clean_word = re.sub(r'[^\w]', '', word.lower())
            if clean_word in cls.VOCABULARY_HINTS:
                vocabulary_suggestions.append({
                    "word": clean_word,
                    "alternatives": cls.VOCABULARY_HINTS[clean_word]
                })

        avg_sentence_length = word_count / sentence_count if sentence_count > 0 else 0

        if word_count < 20:
            overall = "Your response is quite short. Try to elaborate more on your ideas."
        elif len(grammar_issues) > 3:
            overall = "Good effort! Focus on grammar improvement. Review the flagged issues."
        elif vocabulary_suggestions:
            overall = "Well written! Consider using more varied vocabulary to strengthen your writing."
        else:
            overall = "Excellent writing! Good grammar and vocabulary usage."

        return {
            "word_count": word_count,
            "sentence_count": sentence_count,
            "avg_sentence_length": round(avg_sentence_length, 1),
            "grammar_issues": grammar_issues,
            "vocabulary_suggestions": vocabulary_suggestions,
            "overall_feedback": overall
        }


# ============================================================================
# Main Application
# ============================================================================

class LanguageCollaborator:
    """
    Main application class that manages users, exercises, sessions,
    and collaborative features.
    """

    def __init__(self):
        self._users: Dict[str, User] = {}
        self._sessions: Dict[str, Session] = {}
        self._exercises: Dict[int, Exercise] = {}
        self._lock = threading.RLock()
        self._feedback_engine = FeedbackEngine()
        Exercise._id_counter = 0

    # --- User Management ---

    def register_user(self, username: str, password: str,
                      display_name: str = "") -> Dict[str, Any]:
        """Register a new user."""
        if not username or not password:
            return {"success": False, "error": "Username and password are required."}
        if len(username) < 3:
            return {"success": False, "error": "Username must be at least 3 characters."}
        if len(password) < 6:
            return {"success": False, "error": "Password must be at least 6 characters."}
        if not re.match(r'^[a-zA-Z0-9_]+$', username):
            return {"success": False, "error": "Username can only contain letters, numbers, and underscores."}

        with self._lock:
            if username in self._users:
                return {"success": False, "error": "Username already exists."}
            self._users[username] = User(username, password, display_name)

        return {"success": True, "message": f"User '{username}' registered successfully."}

    def login(self, username: str, password: str) -> Dict[str, Any]:
        """Authenticate a user and create a session."""
        if not username or not password:
            return {"success": False, "error": "Username and password are required."}

        with self._lock:
            user = self._users.get(username)
            if not user or not user.verify_password(password):
                return {"success": False, "error": "Invalid username or password."}
            if not user.is_active:
                return {"success": False, "error": "Account is deactivated."}

            session = Session(username)
            self._sessions[session.token] = session

        return {"success": True, "token": session.token, "username": username}

    def logout(self, token: str) -> Dict[str, Any]:
        """Invalidate a user session."""
        with self._lock:
            session = self._sessions.get(token)
            if not session or not session.is_valid:
                return {"success": False, "error": "Invalid session."}
            session.is_valid = False
            del self._sessions[token]

        return {"success": True, "message": "Logged out successfully."}

    def _authenticate(self, token: str) -> Optional[str]:
        """Validate session token and return username if valid."""
        with self._lock:
            session = self._sessions.get(token)
            if session and session.is_valid:
                session.last_activity = datetime.now()
                return session.username
        return None

    # --- Exercise Management ---

    def create_exercise(self, token: str, exercise_type: str, title: str,
                        content: Dict[str, Any]) -> Dict[str, Any]:
        """Create a new language exercise."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}
        if not title or not title.strip():
            return {"success": False, "error": "Exercise title is required."}
        if not content:
            return {"success": False, "error": "Exercise content is required."}

        try:
            ex_type = ExerciseType(exercise_type)
        except ValueError:
            valid_types = [t.value for t in ExerciseType]
            return {"success": False, "error": f"Invalid exercise type. Valid types: {valid_types}"}

        if ex_type == ExerciseType.GRAMMAR_QUIZ:
            questions = content.get("questions", [])
            if not questions:
                return {"success": False, "error": "Grammar quiz must have at least one question."}
            for q in questions:
                if "question" not in q or "correct_answer" not in q:
                    return {"success": False, "error": "Each question must have 'question' and 'correct_answer'."}

        elif ex_type == ExerciseType.VOCABULARY_TEST:
            word_pairs = content.get("word_pairs", [])
            if not word_pairs:
                return {"success": False, "error": "Vocabulary test must have at least one word pair."}
            for pair in word_pairs:
                if "word" not in pair or ("answer" not in pair and "accepted_answers" not in pair):
                    return {"success": False, "error": "Each word pair must have 'word' and 'answer' or 'accepted_answers'."}

        elif ex_type == ExerciseType.WRITING_PROMPT:
            if "prompt" not in content:
                return {"success": False, "error": "Writing prompt must have a 'prompt' field."}

        with self._lock:
            exercise = Exercise(username, ex_type, title.strip(), content)
            self._exercises[exercise.exercise_id] = exercise

        return {
            "success": True,
            "exercise_id": exercise.exercise_id,
            "message": f"Exercise '{title.strip()}' created successfully."
        }

    def share_exercise(self, token: str, exercise_id: int,
                       share_with: List[str] = None,
                       make_public: bool = False) -> Dict[str, Any]:
        """Share an exercise with specific users or make it public."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found."}
            if exercise.creator != username:
                return {"success": False, "error": "Only the creator can share an exercise."}

            if make_public:
                exercise.is_public = True

            if share_with:
                for user in share_with:
                    if user not in self._users:
                        return {"success": False, "error": f"User '{user}' does not exist."}
                    if user not in exercise.shared_with:
                        exercise.shared_with.append(user)

        return {"success": True, "message": "Exercise shared successfully."}

    def get_exercise(self, token: str, exercise_id: int) -> Dict[str, Any]:
        """Retrieve an exercise if the user has access."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found."}

            if not self._has_access(username, exercise):
                return {"success": False, "error": "Access denied."}

        return {
            "success": True,
            "exercise": {
                "exercise_id": exercise.exercise_id,
                "creator": exercise.creator,
                "type": exercise.exercise_type.value,
                "title": exercise.title,
                "content": exercise.content,
                "is_public": exercise.is_public,
                "shared_with": exercise.shared_with,
                "created_at": exercise.created_at.isoformat()
            }
        }

    def list_available_exercises(self, token: str) -> Dict[str, Any]:
        """List all exercises available to the authenticated user."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}

        available = []
        with self._lock:
            for exercise in self._exercises.values():
                if self._has_access(username, exercise):
                    available.append({
                        "exercise_id": exercise.exercise_id,
                        "creator": exercise.creator,
                        "type": exercise.exercise_type.value,
                        "title": exercise.title,
                        "is_public": exercise.is_public
                    })

        return {"success": True, "exercises": available}

    def _has_access(self, username: str, exercise: Exercise) -> bool:
        """Check if a user has access to an exercise."""
        return (exercise.creator == username or
                exercise.is_public or
                username in exercise.shared_with)

    # --- Exercise Submission & Feedback ---

    def submit_exercise(self, token: str, exercise_id: int,
                        answers: Any) -> Dict[str, Any]:
        """Submit answers for an exercise and receive feedback."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found."}
            if not self._has_access(username, exercise):
                return {"success": False, "error": "Access denied."}

        if exercise.exercise_type == ExerciseType.GRAMMAR_QUIZ:
            if not isinstance(answers, list):
                return {"success": False, "error": "Answers must be a list for quiz exercises."}
            feedback = FeedbackEngine.evaluate_quiz(
                exercise.content.get("questions", []), answers
            )

        elif exercise.exercise_type == ExerciseType.VOCABULARY_TEST:
            if not isinstance(answers, list):
                return {"success": False, "error": "Answers must be a list for vocabulary tests."}
            feedback = FeedbackEngine.evaluate_vocabulary(
                exercise.content.get("word_pairs", []), answers
            )

        elif exercise.exercise_type == ExerciseType.WRITING_PROMPT:
            if not isinstance(answers, str):
                return {"success": False, "error": "Answer must be a string for writing prompts."}
            feedback = FeedbackEngine.evaluate_writing(answers)

        else:
            return {"success": False, "error": "Unknown exercise type."}

        submission = {
            "username": username,
            "answers": answers,
            "feedback": feedback,
            "submitted_at": datetime.now().isoformat()
        }

        with self._lock:
            exercise.submissions.append(submission)

        return {"success": True, "feedback": feedback}

    # --- Peer Review ---

    def submit_peer_review(self, token: str, exercise_id: int,
                           target_username: str, rating: int,
                           comments: str) -> Dict[str, Any]:
        """Submit a peer review for another user's exercise submission."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}
        if username == target_username:
            return {"success": False, "error": "You cannot review your own submission."}
        if not isinstance(rating, int) or rating < 1 or rating > 5:
            return {"success": False, "error": "Rating must be an integer between 1 and 5."}
        if not comments or not comments.strip():
            return {"success": False, "error": "Review comments are required."}

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found."}
            if not self._has_access(username, exercise):
                return {"success": False, "error": "Access denied."}

            target_submission = None
            for sub in exercise.submissions:
                if sub["username"] == target_username:
                    target_submission = sub
                    break

            if not target_submission:
                return {"success": False, "error": f"No submission found from user '{target_username}'."}

            review = {
                "reviewer": username,
                "target_user": target_username,
                "rating": rating,
                "comments": comments.strip(),
                "reviewed_at": datetime.now().isoformat()
            }
            exercise.peer_reviews.append(review)

        return {"success": True, "message": "Peer review submitted successfully."}

    def get_peer_reviews(self, token: str, exercise_id: int,
                         for_user: Optional[str] = None) -> Dict[str, Any]:
        """Get peer reviews for an exercise, optionally filtered by user."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}

        with self._lock:
            exercise = self._exercises.get(exercise_id)
            if not exercise:
                return {"success": False, "error": "Exercise not found."}
            if not self._has_access(username, exercise):
                return {"success": False, "error": "Access denied."}

            reviews = exercise.peer_reviews
            if for_user:
                reviews = [r for r in reviews if r["target_user"] == for_user]

        return {"success": True, "reviews": reviews}

    # --- Collaborative Features ---

    def get_user_stats(self, token: str, target_username: Optional[str] = None) -> Dict[str, Any]:
        """Get statistics for a user's activity."""
        username = self._authenticate(token)
        if not username:
            return {"success": False, "error": "Unauthorized. Please log in."}

        target = target_username or username

        with self._lock:
            if target not in self._users:
                return {"success": False, "error": "User not found."}

            exercises_created = sum(
                1 for e in self._exercises.values() if e.creator == target
            )
            submissions_made = sum(
                1 for e in self._exercises.values()
                for s in e.submissions if s["username"] == target
            )
            reviews_given = sum(
                1 for e in self._exercises.values()
                for r in e.peer_reviews if r["reviewer"] == target
            )
            reviews_received = sum(
                1 for e in self._exercises.values()
                for r in e.peer_reviews if r["target_user"] == target
            )

            avg_rating = 0.0
            ratings = [
                r["rating"] for e in self._exercises.values()
                for r in e.peer_reviews if r["target_user"] == target
            ]
            if ratings:
                avg_rating = round(sum(ratings) / len(ratings), 1)

        return {
            "success": True,
            "stats": {
                "username": target,
                "exercises_created": exercises_created,
                "submissions_made": submissions_made,
                "reviews_given": reviews_given,
                "reviews_received": reviews_received,
                "average_rating": avg_rating
            }
        }


# ============================================================================
# Test Suite
# ============================================================================

class TestLanguageCollaborator(unittest.TestCase):
    """Comprehensive test suite for LanguageCollaborator."""

    def setUp(self):
        """Set up test fixtures."""
        self.app = LanguageCollaborator()
        self.app.register_user("alice", "password123", "Alice Smith")
        self.app.register_user("bob", "secure456", "Bob Jones")
        self.app.register_user("carol", "pass789!", "Carol Lee")

        self.alice_token = self.app.login("alice", "password123")["token"]
        self.bob_token = self.app.login("bob", "secure456")["token"]
        self.carol_token = self.app.login("carol", "pass789!")["token"]

    # --- Registration Tests ---

    def test_register_user_success(self):
        result = self.app.register_user("newuser", "newpass123", "New User")
        self.assertTrue(result["success"])

    def test_register_duplicate_username(self):
        result = self.app.register_user("alice", "otherpass1", "Other Alice")
        self.assertFalse(result["success"])
        self.assertIn("already exists", result["error"])

    def test_register_short_username(self):
        result = self.app.register_user("ab", "password123")
        self.assertFalse(result["success"])
        self.assertIn("at least 3", result["error"])

    def test_register_short_password(self):
        result = self.app.register_user("validuser", "short")
        self.assertFalse(result["success"])
        self.assertIn("at least 6", result["error"])

    def test_register_invalid_username_chars(self):
        result = self.app.register_user("user@name", "password123")
        self.assertFalse(result["success"])
        self.assertIn("letters, numbers, and underscores", result["error"])

    def test_register_empty_fields(self):
        result = self.app.register_user("", "password123")
        self.assertFalse(result["success"])

    # --- Login/Logout Tests ---

    def test_login_success(self):
        result = self.app.login("alice", "password123")
        self.assertTrue(result["success"])
        self.assertIn("token", result)

    def test_login_wrong_password(self):
        result = self.app.login("alice", "wrongpass")
        self.assertFalse(result["success"])
        self.assertIn("Invalid", result["error"])

    def test_login_nonexistent_user(self):
        result = self.app.login("nobody", "password123")
        self.assertFalse(result["success"])

    def test_login_empty_fields(self):
        result = self.app.login("", "")
        self.assertFalse(result["success"])

    def test_logout_success(self):
        result = self.app.logout(self.alice_token)
        self.assertTrue(result["success"])

    def test_logout_invalid_token(self):
        result = self.app.logout("invalid_token_xyz")
        self.assertFalse(result["success"])

    def test_action_after_logout(self):
        self.app.logout(self.alice_token)
        result = self.app.list_available_exercises(self.alice_token)
        self.assertFalse(result["success"])
        self.assertIn("Unauthorized", result["error"])

    # --- Multiple Simultaneous Users ---

    def test_multiple_users_logged_in(self):
        self.assertIsNotNone(self.alice_token)
        self.assertIsNotNone(self.bob_token)
        self.assertIsNotNone(self.carol_token)
        self.assertNotEqual(self.alice_token, self.bob_token)
        self.assertNotEqual(self.bob_token, self.carol_token)

    # --- Exercise Creation Tests ---

    def test_create_grammar_quiz(self):
        content = {
            "questions": [
                {"question": "She ___ to school every day.", "options": ["go", "goes", "going"],
                 "correct_answer": "goes", "explanation": "Third person singular uses 'goes'."},
                {"question": "They ___ playing football.", "options": ["is", "are", "am"],
                 "correct_answer": "are", "explanation": "'They' takes 'are'."}
            ]
        }
        result = self.app.create_exercise(self.alice_token, "grammar_quiz", "Basic Verbs", content)
        self.assertTrue(result["success"])
