    # --- Concurrency Tests ---

    def test_concurrent_exercise_creation(self):
        """Test that multiple users can create exercises simultaneously."""
        results = []
        errors = []

        def create_for_user(token, index):
            try:
                content = {"questions": [{"question": f"Q{index}?", "correct_answer": f"A{index}"}]}
                result = self.app.create_exercise(token, "grammar_quiz", f"Concurrent Quiz {index}", content)
                results.append(result)
            except Exception as e:
                errors.append(str(e))

        threads = []
        tokens = [self.alice_token, self.bob_token, self.carol_token]
        for i, token in enumerate(tokens):
            t = threading.Thread(target=create_for_user, args=(token, i))
            threads.append(t)
            t.start()

        for t in threads:
            t.join()

        self.assertEqual(len(errors), 0)
        self.assertEqual(len(results), 3)
        self.assertTrue(all(r["success"] for r in results))

